func TestSaveOAuthTokenCreatesParentDir(t *testing.T) {
	tokenPath := filepath.Join(t.TempDir(), "nested", "youtube-token.json")
	cfg := &Config{TokenPath: tokenPath}
	expiry := time.Now().Add(time.Hour).UTC().Truncate(time.Second)
	if err := cfg.SaveOAuthToken(&oauth2.Token{AccessToken: "access", RefreshToken: "refresh", TokenType: "Bearer", Expiry: expiry}, DefaultYoutubeScopes()); err != nil {
		t.Fatalf("SaveOAuthToken() error = %v", err)
	}
	status := cfg.TokenFileStatus()
	if !status.Exists {
		t.Fatalf("token status = %+v, want exists", status)
	}
	stored, err := cfg.LoadStoredToken()
	if err != nil {
		t.Fatalf("LoadStoredToken() error = %v", err)
	}
	if stored.AccessToken != "access" || stored.RefreshToken != "refresh" {
		t.Fatalf("stored token = %+v, want saved access/refresh", stored)
	}
	if got := stored.ScopesList(); len(got) != len(DefaultYoutubeScopes()) {
		t.Fatalf("stored scopes = %v, want default scopes", got)
	}
}
